```cpp
#include <iostream>
#include <unistd.h>
#include <sys/types.h>
#include <sys/wait.h>
#include <cstdio>

int main() {
    std::cout << "Let's create a new process and make it talk to us! 🤖" << std::endl;

    // Create a pipe
    int pipefd[2];
    if (pipe(pipefd) == -1) {
        perror("Pipe failed");
        return 1;
    }

    // Fork a child process
    pid_t pid = fork();
    if (pid < 0) {
        perror("Fork failed");
        return 1;
    }

    if (pid == 0) { // Child process
        std::cout << "I'm the child! 🌟" << std::endl;

        // Close the write end of the pipe in the child
        close(pipefd[1]);

        // Duplicate the read end of the pipe to stdin and stdout
        dup2(pipefd[0], STDIN_FILENO);
        dup2(pipefd[0], STDOUT_FILENO);

        // Close the pipe
        close(pipefd[0]);

        // Execute a new process
        execlp("bash", "bash", "-c", "echo 'Hello from the child!' && sleep 10", (char*)0);
        perror("Exec failed");
        _exit(1);
    } else { // Parent process
        std::cout << "I'm the parent! 👨‍💻" << std::endl;

        // Close the read end of the pipe in the parent
        close(pipefd[0]);

        // Wait for the child to finish
        wait(NULL);

        // Close the write end of the pipe in the parent
        close(pipefd[1]);

        std::cout << "Child process has finished. 🚀" << std::endl;
    }

    return 0;
}
```

This code sets up a fun little game where the child process talks back to the parent using a pipe. The child process runs a simple bash command to echo a message and then sleeps for 10 seconds. The parent waits for the child to finish and then closes the pipes. Enjoy your coding adventure! 🚀✨
